<template>
	<view class="container">
		<!-- 导航栏 -->
		<view class="nav-bar">
			<view class="status-bar" :style="statusBarStyle"></view>
			<view class="nav-content">
				<view class="back-btn" @tap="goBack">
					<text class="iconfont icon-back"></text>
				</view>
				<view class="title">播放历史</view>
				<view class="placeholder" style="width: 60rpx;"></view>
			</view>
		</view>
		
		<!-- 历史记录列表 -->
		<scroll-view class="history-list" scroll-y :style="contentStyle">
			<!-- 有历史记录时 -->
			<view v-if="historyList.length > 0" class="list-content">
				<view class="list-header">
					<text class="total-count">{{ historyList.length }}条播放记录</text>
				</view>
				<view 
					class="history-item" 
					v-for="(item, index) in historyList" 
					:key="item.id" 
					@tap="playSong(item)"
				>
					<view class="song-info">
						<view class="song-name">{{item.name}}</view>
						<view class="song-artist">{{item.artist}}</view>
					</view>
					<view class="history-time">
						<text>{{formatTime(item.playTime)}}</text>
					</view>
					<view class="song-actions">
						<text class="iconfont icon-play"></text>
					</view>
				</view>
				
				<!-- 清空历史按钮 -->
				<view class="clear-btn" @tap="clearHistory">
					<text class="iconfont icon-delete"></text>
					<text>清空历史记录</text>
				</view>
			</view>
			
			<!-- 空状态 -->
			<view v-if="historyList.length === 0" class="empty-state">
				<image class="empty-image" src="/static/empty.png" mode="aspectFit"></image>
				<view class="empty-text">暂无播放历史</view>
				<view class="empty-tips">您还没有播放过任何歌曲</view>
			</view>
		</scroll-view>
	</view>
</template>

<script>
import { checkLoginStatus } from '@/utils/auth.js'
import { getPlayHistory, clearPlayHistory } from '@/utils/musicData.js'

export default {
	data() {
		return {
			historyList: [],
			statusBarHeight: 25
		}
	},
	computed: {
		// 计算状态栏样式
		statusBarStyle() {
			return {
				height: `${this.statusBarHeight}px`
			}
		},
		// 计算主内容区域样式
		contentStyle() {
			return {
				paddingTop: `${this.statusBarHeight + 100}rpx`
			}
		}
	},
	onLoad() {
		// 获取状态栏高度
		this.getStatusBarHeight();
	},
	onShow() {
		// 检查登录状态
		if (!checkLoginStatus()) {
			uni.navigateTo({
				url: '/pages/login/login'
			})
			return
		}
		
		// 获取历史记录
		this.getHistoryList()
	},
	methods: {
		// 获取状态栏高度
		getStatusBarHeight() {
			try {
				const systemInfo = uni.getSystemInfoSync();
				this.statusBarHeight = systemInfo.statusBarHeight || 25;
			} catch (e) {
				console.error('获取状态栏高度失败:', e);
				this.statusBarHeight = 25; // 默认高度
			}
		},
		
		// 获取历史记录
		getHistoryList() {
			try {
				this.historyList = getPlayHistory();
			} catch (error) {
				console.error('加载历史记录失败：', error);
				uni.showToast({
					title: '加载历史记录失败',
					icon: 'none'
				});
			}
		},
		
		// 播放歌曲
		playSong(song) {
			// 将歌曲添加到播放队列
			uni.$emit('addToPlaylist', song)
			// 跳转到播放页面
			uni.switchTab({
				url: '/pages/player/player'
			})
		},
		
		// 清空历史记录
		clearHistory() {
			uni.showModal({
				title: '提示',
				content: '确定要清空播放历史吗？',
				confirmColor: '#8e71c7',
				success: (res) => {
					if (res.confirm) {
						const result = clearPlayHistory()
						if (result.success) {
							this.historyList = []
							uni.showToast({
								title: result.message,
								icon: 'success'
							})
						} else {
							uni.showToast({
								title: result.message,
								icon: 'none'
							})
						}
					}
				}
			})
		},
		
		// 格式化时间
		formatTime(timestamp) {
			const now = new Date().getTime()
			const diff = now - timestamp
			
			// 小于1小时
			if (diff < 3600000) {
				const minutes = Math.floor(diff / 60000)
				return `${minutes}分钟前`
			}
			
			// 小于24小时
			if (diff < 86400000) {
				const hours = Math.floor(diff / 3600000)
				return `${hours}小时前`
			}
			
			// 小于30天
			if (diff < 2592000000) {
				const days = Math.floor(diff / 86400000)
				return `${days}天前`
			}
			
			// 大于30天
			const date = new Date(timestamp)
			return `${date.getFullYear()}-${String(date.getMonth() + 1).padStart(2, '0')}-${String(date.getDate()).padStart(2, '0')}`
		},
		
		// 返回上一页
		goBack() {
			uni.navigateBack()
		}
	}
}
</script>

